// Flashcards, written questions and R questions — add new content here
const CARDS_BASE = [
  // CM1A — Theory of interest rates
  {module:'CM1A',sub:'int-force',color:'#3D6FD1',topic:'Theory of interest rates',q:'How is the force of interest δ related to the effective annual rate of interest i?',a:'δ = ln(1 + i), equivalently 1 + i = e^δ. It is the continuously-compounded equivalent of i.'},
  {module:'CM1A',sub:'int-rates',color:'#3D6FD1',topic:'Theory of interest rates',q:'How do you convert a nominal rate of interest i^(p) payable p-thly per year to an effective annual rate i?',a:'(1 + i) = (1 + i^(p)/p)^p. Divide the nominal rate by p, add 1, raise to the power p.'},
  {module:'CM1A',sub:'int-tvm',color:'#3D6FD1',topic:'Theory of interest rates',q:'What is the present value of £1 due in n years at effective annual interest rate i?',a:'v^n = (1+i)^{−n}, where v = 1/(1+i) is the discount factor.'},
  {module:'CM1A',sub:'int-inf',color:'#3D6FD1',topic:'Theory of interest rates',q:'If the money rate of interest is i and the inflation rate is f, what is the real rate of interest r?',a:'(1 + r) = (1 + i)/(1 + f), so r ≈ i − f for small rates.'},
  {module:'CM1A',sub:'int-ann',color:'#3D6FD1',topic:'Theory of interest rates',q:'Write down the present value of an annuity-certain of £1 per year for n years (payable annually in arrear).',a:'ä_{n|} = (1 − v^n)/i, where v = 1/(1+i).'},
  {module:'CM1A',sub:'int-duration',color:'#3D6FD1',topic:'Theory of interest rates',q:"State Redington's three conditions for immunisation.",a:"(1) PV assets = PV liabilities. (2) Duration of assets = duration of liabilities. (3) Convexity of assets > convexity of liabilities."},
  {module:'CM1A',sub:'int-term',color:'#3D6FD1',topic:'Theory of interest rates',q:'How is the n-year spot rate s_n related to forward rates?',a:'(1 + s_n)^n = (1 + f_{0,1})(1 + f_{1,2})…(1 + f_{n−1,n}), i.e. the spot accumulation equals the product of successive one-year forward accumulations.'},
  {module:'CM1A',sub:'int-pv',color:'#3D6FD1',topic:'Theory of interest rates',q:'What is the present value of a continuous cashflow ρ(t) paid at rate ρ(t) between times 0 and T?',a:'PV = ∫₀ᵀ ρ(t) · e^{−δt} dt, where δ is the force of interest (assumed constant).'},
  // CM1A — Equation of value
  {module:'CM1A',sub:'eqv-basic',color:'#3D6FD1',topic:'Equation of value',q:'What does an equation of value state?',a:'At a given rate, the present value of the incoming cashflows equals the present value of the outgoing cashflows.'},
  {module:'CM1A',sub:'eqv-bonds',color:'#3D6FD1',topic:'Equation of value',q:'For a fixed-interest bond with coupon rate r%, face value F, redemption value C, and n years to redemption, write the price P at yield i.',a:'P = F·r/100 · a_{n|i} + C · v^n, where a_{n|i} is the annuity factor and v = 1/(1+i).'},
  {module:'CM1A',sub:'eqv-proj',color:'#3D6FD1',topic:'Equation of value',q:'Define the Internal Rate of Return (IRR) of a project.',a:'The IRR is the rate of interest at which the NPV of all cashflows (inflows and outflows) equals zero.'},
  {module:'CM1A',sub:'eqv-loan',color:'#3D6FD1',topic:'Equation of value',q:'For a flat loan repaid by level instalments, what fraction of each instalment is interest vs capital in the first period?',a:'Interest = i × (outstanding loan); capital = instalment − interest. The interest portion is highest early on and declines over time.'},
  {module:'CM1A',sub:'eqv-shares',color:'#3D6FD1',topic:'Equation of value',q:'Under the dividend discount model with constant dividend growth rate g, what is the price of a share paying dividend D next year at required return k?',a:'P = D / (k − g), provided k > g.'},
  // CM1B — Decrement models
  {module:'CM1B',sub:'dec-life',color:'#3D6FD1',topic:'Decrement models',q:'Express ₙpₓ in terms of the force of mortality μ.',a:'ₙpₓ = exp(−∫₀ⁿ μₓ₊ₜ dt). It is the probability of a life aged x surviving n more years.'},
  {module:'CM1B',sub:'dec-multi',color:'#3D6FD1',topic:'Decrement models',q:'What does the probability n|m qx represent?',a:'The probability that a life aged x survives n years and then dies within the following m years.'},
  {module:'CM1B',sub:'dec-contracts',color:'#3D6FD1',topic:'Decrement models',q:'What is the difference between a whole-life assurance and a term assurance?',a:'A whole-life assurance pays a benefit on death whenever it occurs. A term assurance pays only if death occurs within a specified period n; otherwise nothing is paid.'},
  {module:'CM1B',sub:'dec-meanvar',color:'#3D6FD1',topic:'Decrement models',q:'Write the EPV (expected present value) of a whole-life assurance of £1 payable at the end of the year of death, using actuarial notation.',a:'A_x = Σ_{k=0}^{∞} v^{k+1} · k|qₓ, where v = 1/(1+i) and k|qₓ is the probability of dying in year k+1.'},
  {module:'CM1B',sub:'dec-markov',color:'#3D6FD1',topic:'Decrement models',q:'In a multi-state Markov model, what do the Kolmogorov forward equations describe?',a:'They give the rate of change of transition probabilities ₜp_{ij} as a function of transition intensities, allowing us to compute the probability of being in any state at time t.'},
  {module:'CM1B',sub:'dec-mdt',color:'#3D6FD1',topic:'Decrement models',q:'In a multiple decrement table with decrements from cause j, how is the dependent decrement rate q\'_x^(j) related to the independent rate qₓ^(j)?',a:"q'_x^(j) ≈ qₓ^(j) · (1 − ½ Σ_{k≠j} qₓ^(k)) under the UDD assumption — the dependent rate is the independent rate reduced by the probability of earlier decrement from another cause."},
  // CM1B — Pricing and reserving
  {module:'CM1B',sub:'res-grossprem',color:'#3D6FD1',topic:'Pricing & reserving',q:'State the equivalence principle for premium calculation.',a:'The gross premium P is set so that E[PV of outgo] = E[PV of income] at the valuation rate, i.e. the expected profit is zero at outset.'},
  {module:'CM1B',sub:'res-reserve',color:'#3D6FD1',topic:'Pricing & reserving',q:'Give the recursive relationship between successive reserves in words.',a:'(Opening reserve + premium) accumulated with interest, less expected benefits & expenses, divided by the survival probability = closing reserve.'},
  {module:'CM1B',sub:'res-equiv',color:'#3D6FD1',topic:'Pricing & reserving',q:'When do the prospective and retrospective reserves give the same value?',a:'When the valuation basis equals the premium basis — i.e. when reserves and premiums are computed at the same interest rate and mortality table.'},
  {module:'CM1B',sub:'res-mortality',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the death strain at risk (DSAR) for a policy in year t.',a:'DSAR = (benefit payable on death) − (reserve released on death) = S − ₁V. It represents the net amount at risk if a policyholder dies.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'In profit testing, what is the profit vector for year t?',a:'PRO_t = (₁V_{t−1} + P_t − e_t)(1+i) − q_{x+t−1}(S_t + E_t) − p_{x+t−1} · ₁V_t, i.e. income accumulated with interest less expected outgo.'},
  {module:'CM1B',sub:'res-unitlinked',color:'#3D6FD1',topic:'Pricing & reserving',q:'Why are non-unit reserves (sterling reserves) needed for unit-linked contracts?',a:'To cover future negative non-unit cashflows (e.g. guarantee costs, expense charges insufficient to cover expenses). They must be non-negative to avoid a future strain; zeroisation ensures this.'},
  // CS1A — Data analysis
  {module:'CS1A',sub:'data-corr',color:'#2E9C8E',topic:'Data analysis',q:"What does Spearman's rank correlation coefficient measure?",a:'The strength and direction of the monotonic (not necessarily linear) relationship between two variables, computed on their ranks.'},
  {module:'CS1A',sub:'data-pca',color:'#2E9C8E',topic:'Data analysis',q:'What does a scree plot show in PCA?',a:'The eigenvalues (variance explained) of each principal component in decreasing order. A "kink" or "elbow" helps decide how many components to retain.'},
  {module:'CS1A',sub:'data-explore',color:'#2E9C8E',topic:'Data analysis',q:'Name three graphical tools used in exploratory data analysis.',a:'Histogram (distribution shape), boxplot (median, quartiles, outliers), scatter plot (relationships between two variables).'},
  // CS1A — Random variables
  {module:'CS1A',sub:'rv-dist',color:'#2E9C8E',topic:'Random variables',q:'State the mean and variance of a Poisson(λ) distribution.',a:'Mean = λ, Variance = λ. The Poisson is the unique distribution where mean equals variance.'},
  {module:'CS1A',sub:'rv-joint',color:'#2E9C8E',topic:'Random variables',q:'Define the covariance of X and Y and state when it equals zero.',a:'Cov(X,Y) = E[XY] − E[X]E[Y]. It equals zero when X and Y are uncorrelated; independence implies zero covariance, but not vice versa.'},
  {module:'CS1A',sub:'rv-condexp',color:'#2E9C8E',topic:'Random variables',q:'State the law of total expectation.',a:'E[X] = E[E[X|Y]], i.e. the unconditional expectation equals the expectation of the conditional expectation over all values of Y.'},
  {module:'CS1A',sub:'rv-gf',color:'#2E9C8E',topic:'Random variables',q:'What is the moment generating function (MGF) of X and how is it used to find E[X²]?',a:'M(t) = E[e^{tX}]. Then E[X^r] = M^{(r)}(0), the r-th derivative of M(t) evaluated at t = 0.'},
  {module:'CS1A',sub:'rv-clt',color:'#2E9C8E',topic:'Random variables',q:'State the Central Limit Theorem informally.',a:'For iid variables with finite variance, the sample mean tends to Normal(μ, σ²/n) as n → ∞.'},
  {module:'CS1A',sub:'rv-sampling',color:'#2E9C8E',topic:'Random variables',q:'If X₁,…,Xₙ ~ N(μ,σ²) iid, what is the distribution of (n−1)S²/σ²?',a:'Chi-squared with (n−1) degrees of freedom, where S² is the sample variance. It is independent of the sample mean X̄.'},
  // CS1A — Statistical inference
  {module:'CS1A',sub:'inf-est',color:'#2E9C8E',topic:'Statistical inference',q:'When is an estimator θ̂ said to be unbiased?',a:'When E[θ̂] = θ for every possible value of θ — it is correct on average.'},
  {module:'CS1A',sub:'inf-est',color:'#2E9C8E',topic:'Statistical inference',q:'State the Cramér-Rao lower bound.',a:'Var(θ̂) ≥ 1 / I(θ), where I(θ) = −E[∂²ln L/∂θ²] is the Fisher information. An estimator achieving this bound is efficient.'},
  {module:'CS1A',sub:'inf-ci',color:'#2E9C8E',topic:'Statistical inference',q:'How is a 95% confidence interval for a population mean interpreted?',a:'If the procedure were repeated many times, 95% of the resulting intervals would contain the true mean. It is NOT the probability that this particular interval contains μ.'},
  {module:'CS1A',sub:'inf-test',color:'#2E9C8E',topic:'Statistical inference',q:'What is a p-value?',a:'The probability of observing a test statistic at least as extreme as the one obtained, given that H₀ is true. A small p-value is evidence against H₀.'},
  // CS1A — Regression theory (R implementation flashcards are in CS1B section below)
  {module:'CS1A',sub:'reg-lm',color:'#2E9C8E',topic:'Regression',q:'State the OLS estimator for β in the multiple linear regression model Y = Xβ + ε.',a:'β̂ = (X^T X)^{−1} X^T Y, assuming X has full column rank.'},
  {module:'CS1A',sub:'reg-diag',color:'#2E9C8E',topic:'Regression',q:"What does Cook's distance measure in regression diagnostics?",a:"The influence of observation i on all fitted values — it combines leverage and residual size. Large Cook's distance suggests a highly influential point."},
  {module:'CS1A',sub:'reg-glm',color:'#2E9C8E',topic:'Regression & GLMs',q:'Name the three components of a generalised linear model.',a:'A random component (exponential family), a linear predictor Xβ, and a link function g(μ) = Xβ.'},
  {module:'CS1A',sub:'reg-glm',color:'#2E9C8E',topic:'Regression & GLMs',q:'What is the canonical link for a Poisson GLM?',a:'The log link: g(μ) = ln(μ). This ensures the linear predictor can take any real value while μ remains positive.'},
  {module:'CS1A',sub:'reg-glmfit',color:'#2E9C8E',topic:'Regression & GLMs',q:'What is scaled deviance and how is it used to compare nested GLMs?',a:'Scaled deviance = 2(log L_sat − log L_model)/φ. The difference in scaled deviances between two nested models is approximately chi-squared, used as a likelihood ratio test.'},
  // CS1A — Bayesian statistics theory
  {module:'CS1A',sub:'bayes-conj',color:'#2E9C8E',topic:'Bayesian statistics',q:'What is a conjugate prior?',a:'A prior distribution that gives a posterior in the same family, making the Bayesian update tractable.'},
  {module:'CS1A',sub:'bayes-conj',color:'#2E9C8E',topic:'Bayesian statistics',q:"State Bayes' theorem in terms of prior, likelihood, and posterior.",a:'posterior ∝ likelihood × prior, i.e. π(θ|x) ∝ L(θ;x) · π(θ).'},
  {module:'CS1A',sub:'bayes-ci',color:'#2E9C8E',topic:'Bayesian statistics',q:'What is a credible interval?',a:'A Bayesian interval [a,b] such that P(a ≤ θ ≤ b | data) = 0.95 (for 95%). Unlike a frequentist CI, it gives a direct probability statement about the parameter.'},
  {module:'CS1A',sub:'bayes-cred',color:'#2E9C8E',topic:'Bayesian statistics',q:'State the Bühlmann credibility premium formula.',a:"P = Z·X̄ + (1−Z)·μ, where Z = n/(n+k) is the credibility factor, k = σ²/τ² (within-group variance over between-group variance), and μ is the prior mean."},
  // CB1 — Corporate governance
  {module:'CB1',sub:'gov-reg',color:'#6B5DD3',topic:'Corporate governance',q:'What is the primary role of an external auditor?',a:'To give an independent opinion on whether the financial statements give a true and fair view, in accordance with applicable accounting standards.'},
  {module:'CB1',sub:'gov-agency',color:'#6B5DD3',topic:'Corporate governance',q:'What is the agency problem?',a:'Managers (agents) may pursue their own interests rather than maximising shareholder (principal) wealth, due to information asymmetry and misaligned incentives.'},
  {module:'CB1',sub:'gov-ethics',color:'#6B5DD3',topic:'Corporate governance',q:'What does ESG stand for and why is it relevant to corporate governance?',a:'Environmental, Social, and Governance. It measures a company\'s exposure to non-financial risks and ethical conduct, increasingly used by investors and regulators.'},
  {module:'CB1',sub:'gov-finance',color:'#6B5DD3',topic:'Corporate governance',q:'State the shareholder wealth maximisation objective.',a:'Managers should make decisions that maximise the market value of the ordinary shares (market capitalisation), which is the present value of expected future dividends.'},
  // CB1 — How corporates are financed
  {module:'CB1',sub:'fin-capital',color:'#6B5DD3',topic:'Corporate finance',q:'Write the formula for the Weighted Average Cost of Capital.',a:'WACC = (E/V)·re + (D/V)·rd·(1 − T).'},
  {module:'CB1',sub:'fin-capital',color:'#6B5DD3',topic:'Corporate finance',q:"State Modigliani-Miller Proposition I (with taxes).",a:'The value of a geared firm equals the value of an equivalent ungeared firm plus the present value of the tax shield: V_L = V_U + T·D.'},
  {module:'CB1',sub:'fin-deriv',color:'#6B5DD3',topic:'Corporate finance',q:'What is the difference between a put option and a call option?',a:'A call gives the right (not obligation) to buy an asset at the strike price; a put gives the right to sell. Both require paying a premium upfront.'},
  {module:'CB1',sub:'fin-tax',color:'#6B5DD3',topic:'Corporate finance',q:'What is the tax shield on debt?',a:'The tax saving arising because interest payments are tax-deductible: Tax shield = T × r_D × D per year, or PV = T × D for permanent debt.'},
  {module:'CB1',sub:'fin-short',color:'#6B5DD3',topic:'Corporate finance',q:'What is invoice discounting?',a:'A form of short-term finance where a lender advances cash against unpaid invoices; the company retains credit control, and the arrangement is usually confidential.'},
  {module:'CB1',sub:'fin-struct',color:'#6B5DD3',topic:'Corporate finance',q:'Distinguish between loan capital and share capital.',a:'Loan capital (debt) carries a fixed obligation to pay interest and repay principal; holders rank ahead of shareholders on insolvency. Share capital carries no fixed payment; holders receive residual returns.'},
  // CB1 — Evaluating projects
  {module:'CB1',sub:'proj-coc',color:'#6B5DD3',topic:'Evaluating projects',q:'Write the CAPM formula for the required return on equity.',a:'E(r_i) = r_f + β_i (E(r_m) − r_f), where r_f is the risk-free rate and (E(r_m) − r_f) is the market risk premium.'},
  {module:'CB1',sub:'proj-npv',color:'#6B5DD3',topic:'Evaluating projects',q:'Why is NPV preferred over IRR for choosing between mutually exclusive projects?',a:'IRR can rank projects incorrectly when they differ in scale or timing of cashflows, and may give multiple values if cashflows change sign more than once. NPV measures absolute value added.'},
  {module:'CB1',sub:'proj-risk',color:'#6B5DD3',topic:'Evaluating projects',q:'What is a sensitivity analysis in project appraisal?',a:'It measures how much a key input variable (e.g. sales volume, discount rate) must change for the NPV to become zero, indicating the margin of safety.'},
  // CB1 — Accounts
  {module:'CB1',sub:'acc-concepts',color:'#6B5DD3',topic:'Interpreting accounts',q:'State the accruals concept.',a:'Revenue and expenses are recognised when earned or incurred, not when cash is received or paid, so the income statement reflects economic activity for the period.'},
  {module:'CB1',sub:'acc-stmts',color:'#6B5DD3',topic:'Interpreting accounts',q:'What does the statement of cash flows show that the income statement does not?',a:'Actual cash movements — operating, investing and financing — revealing whether the company generates sufficient cash to fund operations and growth, independent of accrual accounting choices.'},
  {module:'CB1',sub:'acc-construct',color:'#6B5DD3',topic:'Interpreting accounts',q:'Compare FIFO and AVCO for inventory valuation in a rising price environment.',a:'FIFO matches older (cheaper) costs to cost of sales, giving higher profit and higher closing stock. AVCO averages costs, giving an intermediate result. FIFO better reflects current stock value on the balance sheet.'},
  {module:'CB1',sub:'acc-ratios',color:'#6B5DD3',topic:'Interpreting accounts',q:"What does a company's gearing measure?",a:'The proportion of debt in its capital structure — debt relative to equity (or to total capital).'},
  {module:'CB1',sub:'acc-proflik',color:'#6B5DD3',topic:'Interpreting accounts',q:'Define Return on Capital Employed (ROCE).',a:'ROCE = EBIT / (Total assets − Current liabilities). It measures how efficiently the company uses its long-term capital to generate operating profit.'},
  {module:'CB1',sub:'acc-consol',color:'#6B5DD3',topic:'Interpreting accounts',q:'When is goodwill recognised in group accounts?',a:'On acquisition, goodwill = consideration paid − fair value of net assets acquired. It appears as an intangible asset and is tested annually for impairment rather than amortised.'},
];

const QUESTIONS = [
  // CM1A — Theory of interest rates
  {module:'CM1A',sub:'int-force',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:4,stem:'Define the force of interest δ and explain its relationship to the effective annual rate of interest i.',model:'The force of interest is the instantaneous, continuously-compounded rate of growth of an investment. It relates to the effective annual rate by δ = ln(1 + i), equivalently 1 + i = e^δ. It is the continuous-time equivalent of i and is convenient when interest is compounded continuously or when rates vary with time.'},
  {module:'CM1A',sub:'int-rates',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:4,stem:'Explain the difference between a nominal rate of interest i^(p) payable p-thly per year and the equivalent effective annual rate, and derive the conversion formula.',model:'A nominal rate i^(p) is quoted per year but compounded p times per year, so each sub-period earns i^(p)/p. The effective annual accumulation is (1 + i^(p)/p)^p, giving (1 + i) = (1 + i^(p)/p)^p. For example, a nominal rate of 12% per annum convertible monthly has an EAR of (1.01)^12 − 1 ≈ 12.68%.'},
  {module:'CM1A',sub:'int-inf',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:4,stem:'Define real and money rates of interest and show how they are related when inflation is present.',model:'The money rate i is the observed market rate; the real rate r adjusts for inflation at rate f. The exact relationship is (1 + r) = (1 + i)/(1 + f), giving r ≈ i − f for small rates. The real rate measures the actual increase in purchasing power.'},
  {module:'CM1A',sub:'int-duration',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:6,stem:"State Redington's three conditions for immunisation and explain the intuition behind each.",model:"(1) PV(assets) = PV(liabilities): the fund is initially matched in value. (2) Duration(assets) = Duration(liabilities): the fund's sensitivity to a small parallel interest-rate shift is the same for both sides. (3) Convexity(assets) > Convexity(liabilities): for larger rate shifts, assets gain more (or lose less) than liabilities, ensuring a surplus under any small rate movement."},
  {module:'CM1A',sub:'int-term',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:5,stem:'Define spot rates and forward rates. Explain the relationship between them.',model:'The n-year spot rate s_n is the yield on a zero-coupon bond maturing in n years. The one-year forward rate f_{t,t+1} is the rate agreed now for lending between years t and t+1. They are linked by (1+s_n)^n = (1+s_{n-1})^{n-1}(1+f_{n-1,n}), i.e. investing for n years at the spot rate is equivalent to investing for n−1 years then rolling over at the implied forward rate.'},
  // CM1A — Equation of value
  {module:'CM1A',sub:'eqv-basic',code:'CM1A',chip:'#3D6FD1',topic:'Equation of value',marks:5,stem:'Explain what an equation of value is and state the conditions required for it to have a unique solution for the rate of interest.',model:'An equation of value equates, at a chosen rate, the present value of money received with the present value of money paid out. A unique solution for the rate exists when all cashflows are certain in amount and timing, and the net cashflow changes sign only once over the term (e.g. outgo followed by income), so that the present value is a monotonic function of the interest rate.'},
  {module:'CM1A',sub:'eqv-proj',code:'CM1A',chip:'#3D6FD1',topic:'Equation of value',marks:5,stem:'Compare the NPV and IRR methods for project appraisal, and explain why NPV is generally preferred.',model:'NPV discounts all cashflows at the required cost of capital and measures the absolute wealth added. IRR finds the rate at which NPV = 0. NPV is preferred because: (1) it measures absolute value; (2) IRR may not be unique if cashflows change sign more than once; (3) for mutually exclusive projects of different scale, IRR can rank them incorrectly, whereas NPV always maximises shareholder wealth.'},
  {module:'CM1A',sub:'eqv-bonds',code:'CM1A',chip:'#3D6FD1',topic:'Equation of value',marks:6,stem:'Derive the price of a fixed-interest bond with annual coupon rate r%, face value F, redemption value C at par, and n years to maturity, at gross redemption yield i.',model:'The bond pays coupons Fr/100 at the end of each year and C at maturity. The price is the PV of all cashflows: P = (Fr/100)·a_{n|i} + C·v^n, where a_{n|i} = (1−v^n)/i and v = 1/(1+i). If P > C the bond is priced above par (coupon rate > yield); if P < C it is priced below par (coupon rate < yield).'},
  // CM1B — Decrement models
  {module:'CM1B',sub:'dec-life',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Define the force of mortality μ_x and derive the expression for ₙpₓ in terms of μ.',model:'μ_x is the instantaneous rate of mortality at exact age x: μ_x = −d/dx [ln(ₙpₓ)] evaluated at n=0. Integrating, ₙpₓ = exp(−∫₀ⁿ μ_{x+t} dt). Under constant force μ, ₙpₓ = e^{−μn}, so mortality follows an exponential distribution.'},
  {module:'CM1B',sub:'dec-contracts',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:4,stem:'Describe the key features of a unit-linked life assurance policy and contrast it with a with-profits policy.',model:'Unit-linked: the policyholder bears the investment risk; premiums buy units in a chosen fund whose value fluctuates. The insurer deducts management charges from the unit fund. With-profits: the insurer bears the investment risk; guaranteed sum assured is topped up by declared reversionary and terminal bonuses. With-profits offers more certainty; unit-linked offers potentially higher growth and more transparency.'},
  {module:'CM1B',sub:'dec-meanvar',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Derive an expression for the variance of the present value of a whole-life assurance benefit of £1 payable at the end of the year of death.',model:'Let Z = v^{K+1} where K is the curtate future lifetime. E[Z] = A_x = Σ v^{k+1} k|q_x. E[Z²] = Σ v^{2(k+1)} k|q_x = ²A_x (evaluated at double the force, or i* = (1+i)²−1). Var(Z) = ²A_x − (A_x)². The variance can also be expressed as ²A_x − A_x², often requiring tables evaluated at twice the standard force of interest.'},
  {module:'CM1B',sub:'dec-markov',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Describe how a multiple-state Markov model can be used to price a long-term care (LTC) insurance contract.',model:'States: (1) Healthy, (2) Disabled/LTC, (3) Dead. Transition intensities: σ (H→D), ρ (D→H recovery), μ_H (H→Dead), μ_D (D→Dead). Kolmogorov equations give transition probabilities. EPV of LTC benefit = integral over time of (probability of being in state D at t) × (benefit rate) × (discount factor). Premiums are set by equivalence principle.'},
  // CM1B — Pricing and reserving
  {module:'CM1B',sub:'res-grossprem',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:5,stem:'Explain the equivalence principle and use it to derive the gross premium P for a 20-year endowment assurance.',model:'The equivalence principle sets P so that E[PV of outgo] = E[PV of income]. For a 20-year endowment assurance of £S on a life aged x, paying S on death within 20 years or at maturity: P·ä_{x:20|} = S·A_{x:20|} + E, where ä is the annuity of premiums, A is the assurance EPV, and E covers expenses. Hence P = (S·A_{x:20|} + expenses) / ä_{x:20|}.'},
  {module:'CM1B',sub:'res-reserve',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:5,stem:'Explain why a life insurer sets up reserves and describe the recursive relationship linking successive policy reserves.',model:'Reserves are held because, for most contracts, early premiums exceed early expected claims, so the insurer must retain funds to meet higher expected claims later and remain solvent. Recursively: take the opening reserve plus the premium, accumulate with interest over the year, deduct the expected benefits and expenses, then divide by the probability of survival to obtain the closing reserve per surviving policyholder.'},
  {module:'CM1B',sub:'res-mortality',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:4,stem:'Define the death strain at risk and explain how it is used to analyse mortality profit.',model:'DSAR = S − V, the difference between the benefit paid on death and the reserve released (which funds it). Expected death cost = q_x · DSAR. Actual death cost = (actual deaths) · DSAR. Mortality profit = (expected − actual) × DSAR: positive profit if fewer deaths than expected. This is used in profit analysis to identify sources of surplus.'},
  {module:'CM1B',sub:'res-unitlinked',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:5,stem:'Explain why non-unit reserves may be required for a unit-linked contract, and describe the zeroisation method.',model:'Non-unit (sterling) reserves cover future negative non-unit cashflows — e.g. when charges deducted from the unit fund are insufficient to cover expenses and death benefits. A negative non-unit cashflow in a future year would require a reserve now. Zeroisation sets any negative projected non-unit cashflow to zero and moves the funding to the current year, ensuring the reserve is never negative and the insurer always has sufficient assets.'},
  // CS1A — Data analysis & Random variables
  {module:'CS1A',sub:'data-corr',code:'CS1A',chip:'#2E9C8E',topic:'Data analysis',marks:4,stem:'Define the Pearson and Spearman correlation coefficients and state when each is preferred.',model:"Pearson's r = Cov(X,Y)/(SD(X)·SD(Y)) measures linear association and assumes continuous data without major outliers. Spearman's ρ is computed on ranks and measures monotonic association — preferred when data are ordinal, non-normal, or contain outliers, since ranks are robust to extreme values."},
  {module:'CS1A',sub:'rv-dist',code:'CS1A',chip:'#2E9C8E',topic:'Random variables',marks:4,stem:'State the properties of the Poisson distribution and give two actuarial applications.',model:'Poisson(λ): P(X=k) = e^{−λ}λ^k/k!, mean = variance = λ, additive (sum of independent Poisson is Poisson). Applications: modelling the number of claims arriving in a period (claim frequency), or the number of defaults in a credit portfolio over a fixed horizon.'},
  {module:'CS1A',sub:'rv-condexp',code:'CS1A',chip:'#2E9C8E',topic:'Random variables',marks:4,stem:'State the law of total expectation and the law of total variance, and illustrate each with an example.',model:'E[X] = E[E[X|Y]] (iterate expectations over Y). Var(X) = E[Var(X|Y)] + Var(E[X|Y]) (within-group variance plus between-group variance). Example: X = aggregate claims, Y = number of claims N. E[X] = E[N]·E[individual claim]; Var(X) = E[N]·Var(claim) + (E[claim])²·Var(N). This is the collective risk model.'},
  // CS1A — Statistical inference
  {module:'CS1A',sub:'inf-est',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:5,stem:'State what it means for an estimator to be unbiased, and explain why unbiasedness alone does not make an estimator a good one.',model:'An estimator θ̂ is unbiased if E[θ̂] = θ for all θ. However unbiasedness ignores variability: a biased estimator with much smaller variance can have a lower mean squared error and so be preferable. Estimators should be judged on the bias–variance trade-off (via MSE), not on bias alone.'},
  {module:'CS1A',sub:'inf-est',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:5,stem:'Describe the method of maximum likelihood estimation and state two desirable asymptotic properties of MLEs.',model:'MLE finds the parameter value θ̂ that maximises the likelihood L(θ;x) = ∏ f(xᵢ;θ), equivalently the log-likelihood. It is found by solving ∂ ln L/∂θ = 0. Asymptotically (large n): MLEs are (1) consistent (converge to true θ), (2) asymptotically efficient (achieve Cramér-Rao bound), and (3) asymptotically normal, making inference straightforward.'},
  {module:'CS1A',sub:'inf-ci',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:4,stem:'Construct a 95% confidence interval for a population mean μ when the population variance σ² is unknown and explain how it differs from the case when σ² is known.',model:'When σ² is unknown, use X̄ ± t_{n-1,0.025} · S/√n, where t_{n-1,0.025} is the critical value from the t-distribution on n−1 degrees of freedom. When σ² is known, use X̄ ± 1.96·σ/√n (normal distribution). The t-interval is wider to account for extra uncertainty in estimating σ; for large n the two are virtually identical.'},
  {module:'CS1A',sub:'rv-clt',code:'CS1A',chip:'#2E9C8E',topic:'CLT',marks:4,stem:'State the Central Limit Theorem and explain why it is useful in actuarial work.',model:'For independent identically distributed variables with finite variance, the distribution of the sample mean (or sum) tends to a normal distribution as the sample size grows. It justifies the normal approximation used for aggregate claims, confidence intervals and hypothesis tests when the exact distribution is unknown or intractable.'},
  // CS1B — Regression & Bayesian
  {module:'CS1B',sub:'cs1b-reg-glm',code:'CS1B',chip:'#2E9C8E',topic:'Regression & GLMs',marks:5,stem:'Explain the purpose of a generalised linear model (GLM) and how it extends ordinary linear regression.',model:'A GLM relates a response from the exponential family to covariates through a linear predictor Xβ and a link function g(μ) = Xβ. It extends linear regression by allowing non-normal responses (e.g. Poisson for claim counts, gamma for claim severities) and a non-identity link, while keeping the model linear in the parameters.'},
  {module:'CS1B',sub:'cs1b-reg-glmfit',code:'CS1B',chip:'#2E9C8E',topic:'Regression & GLMs',marks:5,stem:'Explain what the deviance of a GLM measures and how it is used to compare nested models.',model:'Deviance = 2(log L_saturated − log L_model) measures lack of fit relative to a perfect model. For two nested models (M₁ nested in M₂), the change in deviance Δdev ≈ χ² with degrees of freedom equal to the number of extra parameters. A large Δdev (small p-value) means the extra parameters significantly improve fit.'},
  {module:'CS1B',sub:'cs1b-reg-diag',code:'CS1B',chip:'#2E9C8E',topic:'Regression & GLMs',marks:4,stem:'List four types of residual plot used in linear regression diagnostics and describe what each reveals.',model:'(1) Residuals vs fitted values: checks for non-linearity and heteroscedasticity (funnel pattern). (2) Normal Q-Q plot of residuals: checks normality assumption. (3) Scale-location plot: detects non-constant variance. (4) Residuals vs leverage (Cook\'s distance): identifies influential points that distort the fitted model.'},
  {module:'CS1B',sub:'cs1b-bayes-conj',code:'CS1B',chip:'#2E9C8E',topic:'Bayesian statistics',marks:5,stem:'Explain the Bayesian approach to inference, contrasting it with the frequentist approach, and give an example of a conjugate prior.',model:'Bayesian: treats θ as random with a prior π(θ), updates using data via Bayes\' theorem to get posterior π(θ|x) ∝ L(θ;x)π(θ). Inference is based on the posterior distribution. Frequentist: treats θ as fixed and unknown; inference is based on repeated sampling. Conjugate example: if X|θ ~ Poisson(θ) and θ ~ Gamma(α,β), then θ|x ~ Gamma(α+Σxᵢ, β+n), a tractable posterior in the same family.'},
  {module:'CS1B',sub:'cs1b-bayes-cred',code:'CS1B',chip:'#2E9C8E',topic:'Bayesian statistics',marks:5,stem:'Derive the Bühlmann credibility premium and explain the role of the credibility factor Z.',model:"Bühlmann credibility premium: P = Z·X̄ + (1−Z)·μ, where X̄ is the observed mean, μ is the prior mean, and Z = n/(n+k), k = E[σ²(θ)]/Var(μ(θ)) (within/between ratio). Z → 1 as n → ∞ (data dominates) or as within-risk variance → 0. Z → 0 as within-risk variance is large relative to between-risk variance. It linearly interpolates between pure experience (X̄) and the prior mean."},
  // CB1 — Corporate governance & finance
  {module:'CB1',sub:'fin-capital',code:'CB1',chip:'#6B5DD3',topic:'Capital structure',marks:4,stem:'Define the Weighted Average Cost of Capital (WACC) and explain why the cost of debt is adjusted for tax.',model:'WACC = (E/V)re + (D/V)rd(1 − T) is the blended required return on equity and debt, weighted by market values. Because debt interest is tax-deductible, the effective cost of debt is reduced by the tax shield.'},
  {module:'CB1',sub:'fin-capital',code:'CB1',chip:'#6B5DD3',topic:'Capital structure',marks:5,stem:'Explain the trade-off theory of capital structure and how it determines an optimal debt level.',model:'The trade-off theory says firms balance the tax benefit of debt (interest tax shield, value = T·D for permanent debt) against the costs of financial distress (direct: legal/administration; indirect: lost customers, tighter credit). The optimal debt level is where the marginal tax benefit equals the marginal expected distress cost, giving maximum firm value. Unlike M&M with taxes (all debt is optimal), distress costs prevent 100% debt financing.'},
  {module:'CB1',sub:'gov-agency',code:'CB1',chip:'#6B5DD3',topic:'Corporate governance',marks:5,stem:'Explain the agency problem in the context of maximising shareholder wealth.',model:'The agency problem arises because managers (agents) act on behalf of shareholders (principals) but may pursue their own objectives rather than maximising shareholder wealth. Information asymmetry makes this hard to monitor. It is mitigated by aligning incentives (e.g. performance-related pay, share options), board oversight and corporate governance codes.'},
  {module:'CB1',sub:'proj-coc',code:'CB1',chip:'#6B5DD3',topic:'Evaluating projects',marks:5,stem:'Describe how to estimate the cost of equity for a project using the CAPM, and explain one limitation.',model:'E(r_i) = r_f + β_i(E(r_m) − r_f). Steps: (1) estimate r_f from government bond yields; (2) estimate β_i from regression of stock returns on market returns (or use comparator beta, ungearing then re-gearing); (3) estimate market risk premium from historical data or surveys. Limitation: β is estimated from historical data and may not reflect future risk; the model assumes a single systematic factor, ignoring multifactor risks.'},
  {module:'CB1',sub:'acc-ratios',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:4,stem:'Explain what gearing measures and why a highly geared company is more exposed to interest rate movements.',model:"Gearing measures the proportion of debt in a company's capital structure. A highly geared company has large fixed interest commitments, so a rise in interest rates increases its interest cost sharply and leaves less profit for shareholders."},
  {module:'CB1',sub:'acc-stmts',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:5,stem:'Explain how the statement of cash flows differs from the income statement and why it is useful to analysts.',model:'The income statement shows revenues and expenses on an accruals basis, including non-cash items (depreciation, provisions). The cash flow statement shows actual cash movements under operating, investing and financing activities. Analysts use it to assess liquidity (can the firm pay its bills?), quality of earnings (is profit backed by cash?), and financing strategy. A firm can be profitable yet cash-poor if receivables are high or capex is heavy.'},
  {module:'CB1',sub:'acc-concepts',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:4,stem:'State and explain three fundamental accounting concepts used in preparing financial statements.',model:'(1) Accruals: revenues and expenses are recognised when earned/incurred, not when cash changes hands. (2) Going concern: accounts are prepared assuming the entity continues to trade for the foreseeable future; otherwise assets might be stated at liquidation values. (3) Prudence: gains are not recognised until realised, but losses are recognised as soon as foreseeable — asymmetric treatment to avoid overstating profit.'},

  // ── EXTRA WRITTEN QUESTIONS ────────────────────────────────────────────────

  // CM1A — interest rate extras
  {module:'CM1A',sub:'int-ann',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:5,stem:'Derive the present value of an annuity-immediate of £1 per annum for n years at effective annual rate i, from first principles.',model:'Each payment of £1 is made at times 1, 2, …, n. The PV is v + v² + … + vⁿ = v(1 − vⁿ)/(1−v). Since v = 1/(1+i) and 1−v = i/(1+i), this simplifies to (1 − vⁿ)/i = a_{n|i}. The annuity is a finite geometric series of discount factors.'},
  {module:'CM1A',sub:'int-duration',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:6,stem:'Define Macaulay duration and modified duration. Show how modified duration is used to approximate the change in bond price for a small yield movement.',model:'Macaulay duration D = Σ t·PV(c_t) / P, the weighted average time of cashflows. Modified duration D* = D/(1+i). For a small change Δi in yield, ΔP ≈ −P·D*·Δi. This linear approximation overstates price falls and understates price rises (convexity effect). A bond with D* = 5 loses approximately 5% in price per 1% rise in yield.'},
  {module:'CM1A',sub:'int-term',code:'CM1A',chip:'#3D6FD1',topic:'Theory of interest rates',marks:5,stem:'Explain the expectations theory of the term structure of interest rates and discuss one alternative theory.',model:'Expectations theory: forward rates equal expected future spot rates; an upward-sloping yield curve implies the market expects rates to rise. Alternative — liquidity preference theory: investors demand a term premium for holding longer bonds (illiquidity risk), so the yield curve slopes up even if future spot rates are expected to be flat. Another alternative is market segmentation theory: different investors operate in different maturity segments, so supply and demand in each segment independently determines yields.'},
  {module:'CM1A',sub:'eqv-loan',code:'CM1A',chip:'#3D6FD1',topic:'Equation of value',marks:5,stem:'A loan of £10,000 is repaid by level annual instalments over 10 years at 8% per annum effective. Calculate the annual instalment and the split between interest and capital in the first year.',model:'Annual instalment X = 10000/a_{10|8%}. a_{10|8%} = (1−1.08^{−10})/0.08 ≈ 6.7101, so X ≈ £1,490.29. In year 1: interest = 8% × 10,000 = £800; capital repaid = 1,490.29 − 800 = £690.29. The outstanding balance falls each year, so the interest component declines and the capital component rises over time.'},
  {module:'CM1A',sub:'eqv-shares',code:'CM1A',chip:'#3D6FD1',topic:'Equation of value',marks:4,stem:'Explain the dividend discount model for valuing ordinary shares and state its key assumptions.',model:'Share price P = PV of all expected future dividends. With constant growth g: P = D₁/(k−g) where D₁ is next year\'s dividend and k is the required return. Assumptions: (1) dividends grow at a constant rate g forever; (2) k > g; (3) the model captures all value through dividends. In practice, growth rates change and firms buy back shares rather than pay dividends, limiting the model\'s applicability.'},

  // CM1B — life assurance
  {module:'CM1B',sub:'dec-life',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Define the force of mortality and explain how it is used to construct a life table from scratch.',model:'μ_x is the instantaneous hazard rate at age x: μ_x dt ≈ P(die in [x, x+dt) | alive at x). Given μ_x for all x, we build ₙpₓ = exp(−∫₀ⁿ μ_{x+t} dt). In practice, crude μ_x is estimated from deaths and exposed-to-risk in each age band, then graduated (smoothed) to produce a regular life table. Standard tables (e.g. A1967-70, AM92) are published by actuarial bodies.'},
  {module:'CM1B',sub:'dec-meanvar',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:6,stem:'For a whole-life assurance of £1 payable at end of year of death, show that Var(Z) = ²Aₓ − (Aₓ)², where ²Aₓ is evaluated at twice the force of interest.',model:'The PV random variable is Z = v^{K+1}. E[Z] = Aₓ. E[Z²] = E[v^{2(K+1)}] = Σ v^{2(k+1)} · k|qₓ. But this is just Aₓ evaluated at i* where (1+i*)=( 1+i)², i.e. δ* = 2δ. So E[Z²] = ²Aₓ. Hence Var(Z) = ²Aₓ − Aₓ². The superscript 2 denotes evaluation at double the force of interest, not squaring of the function.'},
  {module:'CM1B',sub:'dec-multi',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Define a joint-life annuity and a last-survivor annuity for two lives. Derive the relationship between them and the single-life annuities.',model:'Joint-life ā_{xy}: pays while both (x) and (y) are alive — ceases on first death. Last-survivor ā_{x̄ȳ}: pays while at least one is alive — ceases on second death. Since the union of {both alive} and {exactly one alive} and {both dead} is exhaustive: ā_{x̄ȳ} = ā_x + ā_y − ā_{xy}. The last-survivor annuity is more expensive; the joint-life is cheaper.'},
  {module:'CM1B',sub:'dec-mdt',code:'CM1B',chip:'#3D6FD1',topic:'Decrement models',marks:5,stem:'Explain the difference between dependent and independent decrement rates in a multiple decrement model, and describe the UDD approach to converting between them.',model:'Dependent rate q\'ₓ^(j): probability of decrement from cause j in [x,x+1] in the presence of all other decrements. Independent rate qₓ^(j): probability of decrement from cause j if it were the only decrement. Under UDD in the multiple decrement table: q\'ₓ^(j) ≈ qₓ^(j)(1 − ½ Σ_{k≠j} qₓ^(k) + ⅓ Σ_{k<l, k,l≠j} qₓ^(k)qₓ^(l) − …). Practically, the approximation q\'ₓ^(j) ≈ qₓ^(j)(1 − ½ Σ_{k≠j} qₓ^(k)) is used for small rates.'},
  {module:'CM1B',sub:'res-grossprem',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:6,stem:'A 10-year term assurance of £100,000 is issued to a life aged 50. Premiums are payable annually in advance. Expenses are 50% of the first premium and 5% of subsequent premiums, plus £20 per policy per year. Outline how you would calculate the gross annual premium using the equivalence principle.',model:'Set EPV(income) = EPV(outgo). Income: P · ä_{50:10|} (annuity of premiums). Outgo: 100,000 · A_{50:10|}^1 (term assurance EPV) + 0.50P (initial expense, at t=0) + 0.05P · ä_{50:10|} (renewal expense proportion) + 0.05P (to correct: renewal on years 2-10, so 0.05P(ä_{50:10|}−1)) + 20 · ä_{50:10|} (per-policy expenses). Rearranging gives P in terms of the assurance and annuity factors read from tables.'},
  {module:'CM1B',sub:'res-profit',code:'CM1B',chip:'#3D6FD1',topic:'Pricing & reserving',marks:5,stem:'Describe the profit testing approach for a unit-linked contract, distinguishing the unit and non-unit funds.',model:'Unit fund: tracks policyholder\'s units; grows at gross investment return; charges (allocation rate, fund management charge, bid-offer spread) are deducted. Non-unit fund: insurer\'s own account; receives charges from unit fund, pays death benefit in excess of unit fund value, pays expenses and commission. Profit vector PRO_t = non-unit fund cashflow for year t, projected forward. Negative future PRO_t values require non-unit reserves (zeroisated to avoid negative reserves).'},

  // CS1A — data & distributions
  {module:'CS1A',sub:'data-pca',code:'CS1A',chip:'#2E9C8E',topic:'Data analysis',marks:5,stem:'Explain the purpose of principal component analysis (PCA) and describe how the principal components are obtained.',model:'PCA reduces the dimensionality of a dataset by finding orthogonal linear combinations of the original variables (principal components) that capture decreasing amounts of variance. The PCs are the eigenvectors of the sample covariance (or correlation) matrix, ordered by their eigenvalues. The first PC has the largest eigenvalue (maximum variance); each subsequent PC is orthogonal to all previous. A scree plot of eigenvalues helps decide how many PCs to retain.'},
  {module:'CS1A',sub:'rv-dist',code:'CS1A',chip:'#2E9C8E',topic:'Random variables',marks:5,stem:'State the key properties of the exponential distribution and explain why it is memoryless.',model:'X ~ Exp(λ): f(x) = λe^{−λx}, mean = 1/λ, variance = 1/λ². Memoryless property: P(X > s+t | X > s) = P(X > t). Proof: P(X > s+t)/P(X > s) = e^{−λ(s+t)}/e^{−λs} = e^{−λt} = P(X>t). This makes the exponential uniquely suited for modelling waiting times between events (e.g. time to next claim), as past elapsed time gives no information about remaining time.'},
  {module:'CS1A',sub:'rv-gf',code:'CS1A',chip:'#2E9C8E',topic:'Random variables',marks:5,stem:'Define the moment generating function (MGF) of a random variable and use it to show that the sum of independent normal random variables is normal.',model:'M_X(t) = E[e^{tX}]. For X ~ N(μ,σ²), M_X(t) = exp(μt + ½σ²t²). For independent X ~ N(μ₁,σ₁²) and Y ~ N(μ₂,σ₂²): M_{X+Y}(t) = M_X(t)·M_Y(t) = exp((μ₁+μ₂)t + ½(σ₁²+σ₂²)t²), which is the MGF of N(μ₁+μ₂, σ₁²+σ₂²). Since the MGF uniquely determines the distribution, X+Y is normal.'},
  {module:'CS1A',sub:'rv-condexp',code:'CS1A',chip:'#2E9C8E',topic:'Random variables',marks:5,stem:'State the law of total variance and apply it to derive the variance of aggregate claims S = X₁+…+X_N, where N is the random claim count and Xᵢ are iid claim severities independent of N.',model:'Var(S) = E[Var(S|N)] + Var(E[S|N]). Given N=n: S = ΣXᵢ, so E[S|N=n] = nμ and Var(S|N=n) = nσ², where μ=E[X], σ²=Var(X). Thus E[Var(S|N)] = E[Nσ²] = σ²E[N] and Var(E[S|N]) = Var(Nμ) = μ²Var(N). So Var(S) = σ²E[N] + μ²Var(N) — the collective risk model formula.'},

  // CS1A — inference
  {module:'CS1A',sub:'inf-test',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:5,stem:'Describe the chi-squared goodness-of-fit test and apply it to test whether a sample of claim counts follows a Poisson distribution.',model:'Divide data into k classes; compute expected frequencies E_i = n·p_i(θ̂) using the estimated parameter. Test statistic X² = Σ(O_i−E_i)²/E_i ~ χ²(k−1−p) under H₀, where p is the number of estimated parameters (p=1 for Poisson with estimated λ). For Poisson: λ̂ = x̄. Merge cells with E_i < 5. Reject H₀ if X² > χ²_{crit}. Limitations: sensitive to grouping choice; approximate for small samples.'},
  {module:'CS1A',sub:'inf-ci',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:4,stem:'Explain what a prediction interval is and how it differs from a confidence interval for the mean.',model:'A confidence interval for the mean covers the true population mean μ with a stated probability over repeated samples. A prediction interval covers a single future observation with that probability — it is always wider because it accounts for both estimation uncertainty in μ and the natural variability of individual observations (variance σ²). Width of PI: X̄ ± t·S√(1+1/n) vs CI: X̄ ± t·S/√n.'},
  {module:'CS1A',sub:'inf-est',code:'CS1A',chip:'#2E9C8E',topic:'Statistical inference',marks:5,stem:'Define the mean squared error (MSE) of an estimator and show that MSE = Variance + Bias².',model:'MSE(θ̂) = E[(θ̂−θ)²]. Write θ̂−θ = (θ̂−E[θ̂]) + (E[θ̂]−θ) = (θ̂−E[θ̂]) + Bias. Squaring and taking expectations: E[(θ̂−E[θ̂])²] = Var(θ̂), the cross-term is zero (since E[θ̂−E[θ̂]]=0), and the bias² term is constant. So MSE = Var(θ̂) + Bias(θ̂)². A biased estimator with small variance can have smaller MSE than an unbiased one with large variance.'},

  // CS1B — regression
  {module:'CS1B',sub:'cs1b-reg-lm',code:'CS1B',chip:'#2E9C8E',topic:'Regression',marks:5,stem:'State the assumptions of simple linear regression and describe how each is checked using residual plots.',model:'Assumptions: (1) Linearity — residuals vs fitted: no pattern (curved pattern suggests a non-linear term needed). (2) Homoscedasticity — scale-location plot: constant spread (funnel shape indicates heteroscedasticity; use WLS or transform Y). (3) Independence — residuals vs order: no trend (relevant for time series). (4) Normality — Q-Q plot of residuals: points on diagonal line (deviations suggest non-normal errors; bootstrap CIs more robust).'},
  {module:'CS1B',sub:'cs1b-reg-glm',code:'CS1B',chip:'#2E9C8E',topic:'Regression & GLMs',marks:6,stem:'A general insurer models claim frequency using a Poisson GLM with log link. Explain the model structure, interpret the coefficients, and describe how exposure is incorporated.',model:'Model: Claims_i ~ Poisson(μ_i), log(μ_i) = log(E_i) + β₀ + β₁x_{i1} + … (E_i = exposure, included as an offset so the response is a rate). Coefficients: exp(β_j) is the multiplicative factor by which the expected claim rate changes for a unit increase in x_j. E.g. exp(β₁)=1.20 means 20% higher rate for that risk factor. Model is fitted by IRLS (iteratively reweighted least squares); deviance replaces RSS for inference.'},
  {module:'CS1B',sub:'cs1b-reg-diag',code:'CS1B',chip:'#2E9C8E',topic:'Regression & GLMs',marks:4,stem:'Describe AIC and BIC as model selection criteria and explain the trade-off each makes.',model:'AIC = −2 log L + 2p; BIC = −2 log L + p log n, where p is the number of parameters and n is the sample size. Both penalise complexity to guard against overfitting, but BIC penalises more heavily for large n, favouring simpler models. AIC targets predictive accuracy; BIC is consistent (selects the true model as n→∞ if it is in the candidate set). Choose the model with the lowest AIC or BIC.'},

  // CS1B — Bayesian
  {module:'CS1B',sub:'cs1b-bayes-conj',code:'CS1B',chip:'#2E9C8E',topic:'Bayesian statistics',marks:5,stem:'A portfolio of policyholders has claim counts Xᵢ | θ ~ Poisson(θ). The prior for θ is Gamma(α,β). Derive the posterior distribution and the Bayes estimate under squared error loss.',model:'Likelihood: L(θ) ∝ θ^{Σxᵢ} e^{−nθ}. Prior: π(θ) ∝ θ^{α−1} e^{−βθ}. Posterior: π(θ|x) ∝ θ^{α+Σxᵢ−1} e^{−(β+n)θ} ~ Gamma(α+Σxᵢ, β+n). Bayes estimate under squared error loss = posterior mean = (α+Σxᵢ)/(β+n). This can be written as a credibility formula: Z·x̄ + (1−Z)·(α/β), where Z = n/(β+n).'},
  {module:'CS1B',sub:'cs1b-bayes-cred',code:'CS1B',chip:'#2E9C8E',topic:'Bayesian statistics',marks:5,stem:'Compare Bayesian credibility premiums and Bühlmann (empirical Bayes) credibility premiums, highlighting the key difference in how parameters are estimated.',model:'Both produce P = Z·X̄ + (1−Z)·μ. Bayesian approach: the prior distribution π(θ) is specified explicitly; μ, σ²(θ), τ² are derived analytically from it. Bühlmann empirical Bayes: the prior is not specified; instead, the structural parameters (μ = E[μ(θ)], σ² = E[σ²(θ)], τ² = Var(μ(θ))) are estimated from the data across risks in the portfolio. The key difference is that Bühlmann requires no parametric assumption about the prior — it is distribution-free.'},

  // CB1 — finance & governance
  {module:'CB1',sub:'fin-deriv',code:'CB1',chip:'#6B5DD3',topic:'Corporate finance',marks:5,stem:'Explain how an interest rate swap works and describe one reason why a company might use one.',model:'In a plain vanilla interest rate swap, one party pays a fixed rate and receives a floating rate (e.g. LIBOR/SOFR) on a notional principal — no principal is exchanged. Uses: (1) a company with floating-rate debt can swap to fixed to reduce interest rate risk; (2) comparative advantage — both parties borrow where they have relative advantage then swap to achieve lower all-in funding cost. Swaps are OTC instruments and carry counterparty credit risk (mitigated by collateral agreements).'},
  {module:'CB1',sub:'fin-capital',code:'CB1',chip:'#6B5DD3',topic:'Capital structure',marks:6,stem:'Critically evaluate the Modigliani-Miller theorem with taxes and explain why firms do not in practice borrow 100% of their capital.',model:'MM with taxes: V_L = V_U + T·D; each £ of debt adds T·rd·D/(r_U) ≈ T·D in value. This implies 100% debt is optimal. In practice, (1) costs of financial distress (default risk, agency costs of debt) increase with leverage and offset the tax shield; (2) personal tax may reduce the corporate tax advantage; (3) debt covenants restrict operations; (4) asymmetric information makes high leverage a negative signal for some firms. Trade-off theory finds an interior optimum; pecking order theory says firms avoid equity issuance rather than targeting a debt ratio.'},
  {module:'CB1',sub:'fin-growth',code:'CB1',chip:'#6B5DD3',topic:'Corporate finance',marks:5,stem:'Explain the motives for mergers and acquisitions and discuss why empirical evidence suggests they often fail to create value for the acquiring company\'s shareholders.',model:'Motives: (1) synergies (cost savings, revenue enhancement); (2) diversification; (3) acquiring undervalued assets; (4) tax benefits; (5) managerial empire-building. Empirical evidence: acquirer share prices typically fall on announcement while target prices rise, suggesting the acquirer overpays. Post-merger, synergies are often harder to realise than projected, cultural integration fails, and management distraction reduces performance. Studies find 50–70% of deals destroy acquirer shareholder value.'},
  {module:'CB1',sub:'proj-cashflow',code:'CB1',chip:'#6B5DD3',topic:'Evaluating projects',marks:5,stem:'Identify the relevant cashflows to include in the NPV appraisal of a capital project and explain why certain items should be excluded.',model:'Include: incremental revenues and operating costs, tax on operating profit, capital allowances (tax relief on capex), working capital changes, terminal salvage value. Exclude: (1) sunk costs (already spent, not affected by decision); (2) financing charges — the cost of capital is reflected in the discount rate; (3) allocated fixed overheads that do not change. Only incremental, after-tax cashflows that result from taking the project are relevant to the decision.'},
  {module:'CB1',sub:'acc-construct',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:5,stem:'Explain the straight-line and reducing-balance methods of depreciation and discuss how the choice affects reported profit.',model:'Straight-line: annual charge = (Cost − Residual)/Life. Reducing balance: charge = rate × NBV; higher charges early, lower later. Straight-line gives stable charges; reducing balance front-loads expense. A company switching from reducing balance to straight-line will report higher profits in early years. Under IAS 16, the method should reflect the pattern in which economic benefits are consumed. The choice affects NBV on the balance sheet, ROCE, and asset turnover ratios.'},
  {module:'CB1',sub:'acc-consol',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:5,stem:'Explain the acquisition method of consolidation. How is goodwill calculated and treated in the group accounts?',model:'In a business combination: (1) identify the acquirer; (2) measure consideration transferred (cash + shares at fair value); (3) measure identifiable assets acquired and liabilities assumed at fair value at acquisition date; (4) goodwill = consideration + NCI − fair value of net assets. Under IFRS 3, goodwill is not amortised but tested annually for impairment (any write-down is permanent). A bargain purchase (negative goodwill) is recognised immediately in profit or loss.'},
  {module:'CB1',sub:'acc-insbank',code:'CB1',chip:'#6B5DD3',topic:'Interpreting accounts',marks:4,stem:'Describe two key differences between the financial statements of an insurance company and those of a non-financial company.',model:'(1) Technical provisions / insurance liabilities: a major balance sheet liability representing the estimated cost of all claims incurred (IBNR, outstanding) and unearned premiums — no equivalent in manufacturing. (2) Investment-heavy assets: a large proportion of assets are financial investments held to back liabilities, with unrealised gains/losses affecting comprehensive income. Additionally, regulatory capital (Solvency II SCR) rather than accounting equity drives decisions, and premium income differs fundamentally from revenue recognition in other sectors.'},
];


// ── EXTRA CARDS ──────────────────────────────────────────────────────────────
const EXTRA_CARDS = [
  // CM1A — cashflows & annuities
  {module:'CM1A',sub:'int-cashflow',color:'#3D6FD1',topic:'Theory of interest rates',q:'What is an annuity-due and how does its present value differ from an annuity-immediate?',a:'An annuity-due pays at the start of each period; an annuity-immediate pays at the end. ä_{n|} = (1+i)·a_{n|}, i.e. each payment is received one period earlier, so the annuity-due is worth a factor (1+i) more.'},
  {module:'CM1A',sub:'int-cashflow',color:'#3D6FD1',topic:'Theory of interest rates',q:'What is a perpetuity and what is its present value?',a:'A perpetuity pays £1 per year forever. PV = 1/i (annuity-immediate) or 1/d (annuity-due), where d = i/(1+i) is the rate of discount.'},
  {module:'CM1A',sub:'int-pv',color:'#3D6FD1',topic:'Theory of interest rates',q:'How do you find the accumulated value at time T of a discrete cashflow c_t paid at time t?',a:'AV = Σ c_t · (1+i)^{T−t}. Each cashflow is accumulated forward to time T at the rate of interest.'},
  {module:'CM1A',sub:'int-ann',color:'#3D6FD1',topic:'Theory of interest rates',q:'Write the accumulation factor s_{n|} for an annuity-immediate and express it in terms of a_{n|}.',a:'s_{n|} = ((1+i)^n − 1)/i = (1+i)^n · a_{n|}. It is the value at time n of £1 paid at the end of each year for n years.'},
  {module:'CM1A',sub:'int-ann',color:'#3D6FD1',topic:'Theory of interest rates',q:'What is a continuous annuity ā_{n|} and how is it computed?',a:'ā_{n|} = ∫₀ⁿ e^{−δt} dt = (1 − e^{−δn})/δ. It is the PV of £1 per year paid continuously for n years.'},
  {module:'CM1A',sub:'int-duration',color:'#3D6FD1',topic:'Theory of interest rates',q:'Define Macaulay duration.',a:'Macaulay duration D = (Σ t · PV(c_t)) / (Σ PV(c_t)) — the weighted average time to receipt of cashflows, with PV weights. It measures price sensitivity to yield changes.'},
  {module:'CM1A',sub:'int-duration',color:'#3D6FD1',topic:'Theory of interest rates',q:'How is modified duration related to Macaulay duration?',a:"Modified duration D* = D/(1+i). The percentage change in price for a small change in yield is approximately −D*·Δi, i.e. dP/P ≈ −D*·di."},
  // CM1A — loans & bonds
  {module:'CM1A',sub:'eqv-loan',color:'#3D6FD1',topic:'Equation of value',q:'What is the outstanding loan balance immediately after the k-th instalment under a level annuity loan?',a:'Prospective: PV of remaining instalments, L_k = X · a_{n−k|i}. Retrospective: L_k = L·(1+i)^k − X·s_{k|i}.'},
  {module:'CM1A',sub:'eqv-loan',color:'#3D6FD1',topic:'Equation of value',q:'Define the Annual Percentage Rate (APR) of a loan.',a:'The APR is the effective annual interest rate i at which the present value of all repayments equals the amount borrowed — it is the IRR from the lender\'s perspective, expressed as a percentage per annum.'},
  {module:'CM1A',sub:'eqv-bonds',color:'#3D6FD1',topic:'Equation of value',q:'What happens to the price of a fixed-coupon bond when market yields rise?',a:'The price falls. Bond prices and yields move inversely: a higher discount rate reduces the PV of future coupon and redemption cashflows, so the bond is worth less.'},
  {module:'CM1A',sub:'eqv-bonds',color:'#3D6FD1',topic:'Equation of value',q:'What is the par yield of a bond?',a:'The coupon rate at which the bond is priced exactly at par (P = C). At the par yield, coupon income exactly compensates the investor for the time value of money, so no capital gain or loss is expected.'},
  {module:'CM1A',sub:'eqv-shares',color:'#3D6FD1',topic:'Equation of value',q:'Under the dividend discount model with no dividend growth, what is the share price?',a:'P = D/k, where D is the constant annual dividend and k is the required return — equivalent to a perpetuity.'},
  {module:'CM1A',sub:'eqv-proj',color:'#3D6FD1',topic:'Equation of value',q:'What is the payback period of a project and what is its main weakness?',a:'The time until cumulative cashflows turn positive (the initial investment is recovered). Its main weakness is that it ignores cashflows after the payback date and does not account for the time value of money.'},
  // CM1B — life tables
  {module:'CM1B',sub:'dec-life',color:'#3D6FD1',topic:'Decrement models',q:'What is the curtate future lifetime K_x?',a:'K_x = ⌊T_x⌋ is the integer part of the complete future lifetime T_x — the number of complete years lived after age x. K_x takes values 0, 1, 2, … with P(K_x = k) = k|q_x.'},
  {module:'CM1B',sub:'dec-life',color:'#3D6FD1',topic:'Decrement models',q:'State the relationship between q_x, p_x, and μ_x under the assumption of a constant force of mortality.',a:'Under constant μ over [x, x+1]: q_x = 1 − e^{−μ} and p_x = e^{−μ}.'},
  {module:'CM1B',sub:'dec-life',color:'#3D6FD1',topic:'Decrement models',q:'What is the UDD (Uniform Distribution of Deaths) assumption and what does it imply?',a:'UDD assumes deaths are spread uniformly within each year of age: t·q_x = t · q_x for 0 ≤ t ≤ 1. It implies the force of mortality increases within the year and deaths occur on average at mid-year.'},
  {module:'CM1B',sub:'dec-multi',color:'#3D6FD1',topic:'Decrement models',q:'Define joint-life and last-survivor annuities for two lives aged x and y.',a:'Joint-life annuity ā_{xy} pays while both are alive (stops on first death). Last-survivor annuity ā_{x̄ȳ} pays while at least one is alive. They satisfy ā_{xy} + ā_{x̄ȳ} = ā_x + ā_y.'},
  // CM1B — assurance EPVs
  {module:'CM1B',sub:'dec-meanvar',color:'#3D6FD1',topic:'Decrement models',q:'What is the EPV of a whole-life immediate annuity of £1 p.a. for a life aged x, and how is it related to A_x?',a:'ā_x = (1 − A_x)/δ (continuous) or a_x = (1 − A_x)/i (discrete, end-of-year). These follow from the identity that the benefit can be represented as a perpetuity minus the assurance.'},
  {module:'CM1B',sub:'dec-meanvar',color:'#3D6FD1',topic:'Decrement models',q:'What is a term assurance A_{x:n|}^1 and how does it differ from A_{x:n|}?',a:'A_{x:n|}^1 (term assurance) pays only on death within n years; A_{x:n|} (endowment assurance) pays on death within n years OR at maturity. A_{x:n|} = A_{x:n|}^1 + A_{x:n|}^{  1} where A_{x:n|}^{  1} = v^n · n·p_x is the pure endowment.'},
  // CM1B — reserving extras
  {module:'CM1B',sub:'res-equiv',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the prospective reserve and the retrospective reserve.',a:'Prospective: EPV of future benefits & expenses minus EPV of future premiums (forward-looking). Retrospective: accumulated value of past premiums minus accumulated cost of past benefits & expenses (backward-looking). Both equal the same value when computed on the premium basis.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is the purpose of profit testing a life insurance contract?',a:'To project the expected profit emerging each year, allowing the insurer to: (1) set premiums, (2) check adequacy of reserves, (3) assess profitability and return on capital, (4) identify years of expected loss that may require non-unit reserves.'},
  {module:'CM1B',sub:'dec-mdt',color:'#3D6FD1',topic:'Decrement models',q:'Give an example of a multiple decrement model in pensions.',a:'A pension scheme member can leave by: death, ill-health retirement, age retirement, or withdrawal (resignation). Each has its own decrement rate, and the table combines all decrements to give probabilities of remaining active year by year.'},
  // CS1A extras — data & distributions
  {module:'CS1A',sub:'data-aims',color:'#2E9C8E',topic:'Data analysis',q:'What is meant by reproducibility in data analysis?',a:'That another analyst can re-run exactly the same steps on the same data and obtain identical results. It requires documenting code, data sources, and software versions — facilitated by tools like R Markdown or version control.'},
  {module:'CS1A',sub:'data-explore',color:'#2E9C8E',topic:'Data analysis',q:'What does a boxplot display?',a:'The five-number summary: minimum, lower quartile (Q1), median (Q2), upper quartile (Q3), maximum. Whiskers extend to the most extreme non-outlier values; points beyond 1.5×IQR from the box are plotted individually as potential outliers.'},
  {module:'CS1A',sub:'data-pca',color:'#2E9C8E',topic:'Data analysis',q:'What are the principal components in PCA?',a:'Linear combinations of the original variables that are mutually uncorrelated and capture decreasing amounts of variance. The first PC has maximum variance; each subsequent PC is orthogonal to all previous ones.'},
  {module:'CS1A',sub:'rv-dist',color:'#2E9C8E',topic:'Random variables',q:'State the mean and variance of a Normal(μ, σ²) distribution.',a:'Mean = μ, Variance = σ². The normal is symmetric about μ; ≈68% of values lie within ±1σ, ≈95% within ±2σ.'},
  {module:'CS1A',sub:'rv-dist',color:'#2E9C8E',topic:'Random variables',q:'What is the lognormal distribution and when is it used in actuarial work?',a:'If ln(X) ~ N(μ, σ²) then X is lognormal. Used for claim severities, asset prices and mortality improvements — all positive and right-skewed. Mean = e^{μ+σ²/2}, Variance = e^{2μ+σ²}(e^{σ²}−1).'},
  {module:'CS1A',sub:'rv-dist',color:'#2E9C8E',topic:'Random variables',q:'What is the Pareto distribution and why is it used for insurance claims?',a:'X ~ Pareto(α, λ) has a heavy right tail: P(X>x) = (λ/(λ+x))^α. Used when large claims are much more likely than under a normal model — models claim severity for catastrophe or liability lines.'},
  {module:'CS1A',sub:'rv-joint',color:'#2E9C8E',topic:'Random variables',q:'What is the difference between independence and zero correlation?',a:'Independence implies zero correlation, but zero correlation does NOT imply independence (except for jointly normal random variables). Two variables can have Cov(X,Y)=0 yet be dependent (e.g. Y=X²).'},
  {module:'CS1A',sub:'rv-sampling',color:'#2E9C8E',topic:'Random variables',q:'What is the t-distribution and when is it used instead of the normal?',a:'The t-distribution with ν degrees of freedom has heavier tails than the normal. It is used for inference on a normal mean when σ² is unknown: (X̄−μ)/(S/√n) ~ t_{n−1}. As ν→∞ it converges to N(0,1).'},
  {module:'CS1A',sub:'rv-sampling',color:'#2E9C8E',topic:'Random variables',q:'Define the F-distribution and state one use.',a:'If U ~ χ²(m) and V ~ χ²(n) independently, then F = (U/m)/(V/n) ~ F(m,n). Used to compare two sample variances, and in ANOVA to test whether group means differ.'},
  // CS1A — inference extras
  {module:'CS1A',sub:'inf-est',color:'#2E9C8E',topic:'Statistical inference',q:'What is the bootstrap method of estimation?',a:'Resample the data with replacement B times, compute the statistic of interest on each resample, and use the resulting empirical distribution to estimate standard errors or confidence intervals — useful when no closed-form formula exists.'},
  {module:'CS1A',sub:'inf-test',color:'#2E9C8E',topic:'Statistical inference',q:'State the chi-squared goodness-of-fit test statistic and its null distribution.',a:'X² = Σ (O_i − E_i)²/E_i, summed over k cells. Under H₀ (specified distribution), X² is approximately χ²(k−1−p), where p is the number of parameters estimated from the data.'},
  {module:'CS1A',sub:'inf-test',color:'#2E9C8E',topic:'Statistical inference',q:'What is a Type I and Type II error in hypothesis testing?',a:'Type I: rejecting H₀ when it is true (false positive); probability = significance level α. Type II: failing to reject H₀ when it is false (false negative); probability = β. Power = 1 − β.'},
  {module:'CS1A',sub:'inf-ci',color:'#2E9C8E',topic:'Statistical inference',q:'How do you construct a 95% CI for a Poisson rate λ from n observations with total count x?',a:'Use x ~ Poisson(nλ). Approximate CI: x/n ± 1.96√(x)/n. Exact CI uses chi-squared quantiles: [χ²(2x, 0.025)/(2n), χ²(2x+2, 0.975)/(2n)].'},
  // CS1A — regression theory extras
  {module:'CS1A',sub:'reg-lm',color:'#2E9C8E',topic:'Regression',q:'What does R² measure in linear regression and what is its main limitation?',a:'R² = 1 − SS_res/SS_tot is the proportion of variance in Y explained by the model. Limitation: it always increases when predictors are added, even useless ones — use adjusted R² or AIC/BIC to penalise for model complexity.'},
  {module:'CS1A',sub:'reg-lm',color:'#2E9C8E',topic:'Regression',q:'State the four assumptions of the classical linear regression model.',a:'(1) Linearity: E[Y|X] = Xβ. (2) Homoscedasticity: Var(ε_i) = σ² (constant). (3) Independence: errors are uncorrelated. (4) Normality: ε ~ N(0, σ²I). Violations are diagnosed via residual plots.'},
  {module:'CS1A',sub:'reg-diag',color:'#2E9C8E',topic:'Regression',q:'What is leverage in regression and why does high leverage matter?',a:"Leverage h_{ii} = (H)_{ii} (the i-th diagonal of the hat matrix H = X(X'X)^{-1}X') measures how far observation i's predictors are from the mean. High leverage means x_i has potential to pull the regression line, so even a moderate residual can be influential."},
  {module:'CS1A',sub:'reg-glm',color:'#2E9C8E',topic:'Regression & GLMs',q:'What is the canonical link for a Gamma GLM?',a:'The reciprocal (inverse) link: g(μ) = 1/μ, giving the linear predictor as 1/μ = Xβ. The log link is often used instead because it ensures μ > 0 and is easier to interpret.'},
  {module:'CS1A',sub:'reg-glmfit',color:'#2E9C8E',topic:'Regression & GLMs',q:'What are Pearson residuals in a GLM?',a:'r_P = (y − μ̂)/√V(μ̂), standardised by the square root of the variance function. They should be approximately N(0,1) if the model is correct; patterns indicate model misspecification.'},
  // CS1A — Bayesian theory extras
  {module:'CS1A',sub:'bayes-conj',color:'#2E9C8E',topic:'Bayesian statistics',q:'If X|θ ~ Binomial(n,θ) and θ ~ Beta(α,β), what is the posterior?',a:'θ|x ~ Beta(α+x, β+n−x). The Beta-Binomial is the classic conjugate pair. Posterior mean = (α+x)/(α+β+n), a weighted average of prior mean α/(α+β) and sample proportion x/n.'},
  {module:'CS1A',sub:'bayes-ci',color:'#2E9C8E',topic:'Bayesian statistics',q:'What is the highest posterior density (HPD) region?',a:'The shortest credible interval such that every point inside has higher posterior density than every point outside. For symmetric unimodal posteriors it equals the equal-tailed interval; for skewed posteriors it differs.'},
  {module:'CS1A',sub:'bayes-cred',color:'#2E9C8E',topic:'Bayesian statistics',q:'In credibility theory, what does a credibility factor Z close to 1 mean?',a:'Z close to 1 means the observed data are given high weight relative to the prior mean — this occurs when n is large (much data) or when within-risk variance is small relative to between-risk variance (risk is homogeneous).'},
  // CB1 — governance extras
  {module:'CB1',sub:'gov-reg',color:'#6B5DD3',topic:'Corporate governance',q:'What is the role of the audit committee within corporate governance?',a:'An independent sub-committee of the board (mainly non-executive directors) that oversees financial reporting, internal controls, the internal audit function, and the relationship with external auditors.'},
  {module:'CB1',sub:'gov-ethics',color:'#6B5DD3',topic:'Corporate governance',q:'What is corporate social responsibility (CSR)?',a:'A company\'s voluntary commitment to manage its social, environmental and ethical impact beyond legal requirements — including community engagement, environmental stewardship and ethical supply chains.'},
  {module:'CB1',sub:'gov-finance',color:'#6B5DD3',topic:'Corporate governance',q:'List four stakeholders of a company other than shareholders.',a:'Employees (jobs, pay), creditors (interest/repayment), customers (product quality), suppliers (trade terms), government (taxes, regulation), local communities (employment, environment).'},
  // CB1 — financing extras
  {module:'CB1',sub:'fin-medium',color:'#6B5DD3',topic:'Corporate finance',q:'What is the difference between hire purchase and a finance lease?',a:'Hire purchase: the asset is eventually owned by the lessee after all instalments are paid. Finance lease: ownership stays with the lessor, but substantially all risks and rewards transfer to the lessee; the asset and liability appear on the lessee\'s balance sheet.'},
  {module:'CB1',sub:'fin-alt',color:'#6B5DD3',topic:'Corporate finance',q:'What is peer-to-peer (P2P) lending?',a:'An online platform that directly matches borrowers with individual lenders, bypassing banks. Lenders earn interest; borrowers get funds faster, often at competitive rates. Risk: no deposit protection; platform default risk.'},
  {module:'CB1',sub:'fin-instr',color:'#6B5DD3',topic:'Corporate finance',q:'What is a convertible bond?',a:'A bond that gives the holder the right to convert into ordinary shares at a pre-set conversion price. It offers downside protection (bond floor) with upside equity participation. Issued at a lower coupon than plain debt.'},
  {module:'CB1',sub:'fin-instr',color:'#6B5DD3',topic:'Corporate finance',q:'What is an asset-backed security (ABS)?',a:'A security whose cashflows are backed by a pool of underlying assets (e.g. mortgages, credit card receivables). The originator sells the assets to a special purpose vehicle (SPV) which issues the ABS, transferring credit risk to investors.'},
  {module:'CB1',sub:'fin-deriv',color:'#6B5DD3',topic:'Corporate finance',q:'What is the difference between exchange-traded and OTC derivatives?',a:'Exchange-traded: standardised contracts on a regulated exchange with a central counterparty (clearing house) eliminating counterparty risk. OTC: customised bilateral contracts — more flexible but carry counterparty credit risk and less transparency.'},
  {module:'CB1',sub:'fin-issue',color:'#6B5DD3',topic:'Corporate finance',q:'What is an IPO and what are the main methods of flotation?',a:'Initial Public Offering — first sale of shares to the public. Methods: (1) Offer for sale (fixed price or book-built), (2) Placing (shares sold to institutional investors), (3) Introduction (existing shares admitted, no new money raised), (4) Public offer.'},
  {module:'CB1',sub:'fin-growth',color:'#6B5DD3',topic:'Corporate finance',q:'What is the difference between a merger and an acquisition?',a:'Merger: two companies combine to form a new entity (roughly equal partners). Acquisition: one company (the acquirer) purchases a controlling interest in another (the target), which may retain its legal identity. Most "mergers" are effectively acquisitions.'},
  {module:'CB1',sub:'fin-capital',color:'#6B5DD3',topic:'Corporate finance',q:'State the pecking order theory of capital structure.',a:'Firms prefer internally generated funds first, then debt, then equity as a last resort. This avoids signalling problems: issuing equity signals managers think the stock is overvalued, depressing the price. Debt has a smaller signalling effect.'},
  // CB1 — project appraisal extras
  {module:'CB1',sub:'proj-cashflow',color:'#6B5DD3',topic:'Evaluating projects',q:'Why are sunk costs excluded from project appraisal?',a:'Sunk costs have already been incurred and cannot be recovered regardless of the decision. Only incremental (relevant) future cashflows that differ between the options should be included in NPV analysis.'},
  {module:'CB1',sub:'proj-risk',color:'#6B5DD3',topic:'Evaluating projects',q:'What is the certainty equivalent approach to risk in project appraisal?',a:'Replace risky cashflows with their certainty equivalents (smaller, risk-free amounts the decision-maker finds equally attractive) and discount at the risk-free rate. This separates risk adjustment from time preference, unlike the risk-adjusted discount rate method.'},
  {module:'CB1',sub:'proj-ident',color:'#6B5DD3',topic:'Evaluating projects',q:'What is a probability-impact matrix used for in risk assessment?',a:'It plots identified risks on a grid of probability (low to high) vs impact (low to high). Risks in the high-probability / high-impact quadrant are prioritised for mitigation. It is qualitative and helps communicate risk exposure to stakeholders.'},
  // CB1 — accounts extras
  {module:'CB1',sub:'acc-purpose',color:'#6B5DD3',topic:'Interpreting accounts',q:'What is the TCFD framework?',a:'Task Force on Climate-related Financial Disclosures — recommends companies disclose how climate risks affect governance, strategy, risk management, and key metrics/targets. Increasingly mandatory for listed companies.'},
  {module:'CB1',sub:'acc-construct',color:'#6B5DD3',topic:'Interpreting accounts',q:'What is goodwill and how is it recorded on the balance sheet?',a:'Goodwill = price paid for a business above the fair value of its identifiable net assets. It reflects intangibles like brand and customer relationships. Under IFRS it is not amortised but tested annually for impairment; under US GAAP historically amortised.'},
  {module:'CB1',sub:'acc-insbank',color:'#6B5DD3',topic:'Interpreting accounts',q:'What are technical provisions in an insurance company\'s balance sheet?',a:'Liabilities representing the insurer\'s estimate of future claims and expenses for policies in force. They include the claims reserve (IBNR + outstanding claims) and unearned premium reserve (for general insurance) or policy reserves (for life insurance).'},
  {module:'CB1',sub:'acc-consol',color:'#6B5DD3',topic:'Interpreting accounts',q:'How is an associate company treated in group accounts under IFRS?',a:'An associate (20–50% ownership, significant influence) is accounted for using the equity method: the investment appears as a single line on the balance sheet at cost plus share of post-acquisition profits; the income statement shows the group\'s share of the associate\'s profit.'},
  {module:'CB1',sub:'acc-proflik',color:'#6B5DD3',topic:'Interpreting accounts',q:'What does the current ratio measure and what level is generally considered healthy?',a:'Current ratio = Current assets / Current liabilities. It measures short-term liquidity. A ratio around 1.5–2 is often cited as comfortable, though industry norms vary. Below 1 suggests potential difficulty meeting short-term obligations.'},
  {module:'CB1',sub:'acc-proflik',color:'#6B5DD3',topic:'Interpreting accounts',q:'What is EBITDA and why do analysts use it?',a:'Earnings Before Interest, Tax, Depreciation and Amortisation. It approximates operating cash generation, removing the effect of financing (interest), tax jurisdiction, and non-cash accounting charges — useful for comparing operating performance across companies or capital structures.'},

  // ── CM1B RESERVES & PROFIT TESTING EXTRAS ────────────────────────────────
  {module:'CM1B',sub:'res-equiv',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the net premium reserve.',a:'The reserve calculated using the net premium (with no expense loading) and the premium basis mortality/interest. It equals EPV(future benefits) − P_net × a_{x+t:n−t|}, evaluated at the valuation date. It is generally larger than the gross premium reserve because P_net > P_gross (no expense loading cuts the premium).'},
  {module:'CM1B',sub:'res-grossprem',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the gross premium reserve.',a:'The reserve calculated using the gross premium (including expense loading) and the valuation basis: EPV(future benefits + future expenses) − P_gross × EPV(future premium annuity). Because the gross premium exceeds the net premium, the gross premium reserve is smaller and can be negative in early years.'},
  {module:'CM1B',sub:'res-equiv',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the prospective reserve.',a:'The prospective reserve is the expected present value of future benefits and expenses minus the expected present value of future premiums, all calculated at the valuation date using the valuation basis. It is "forward-looking": what does the insurer still owe, net of what the policyholder will still pay?'},
  {module:'CM1B',sub:'res-reserve',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the retrospective reserve.',a:'The retrospective reserve is the accumulated value of past premium income less past benefits and expenses, brought forward to the valuation date using the premium basis. It answers: how much has been banked on behalf of this policy so far? It equals the prospective reserve when both are computed on the same basis.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is the asset share of a policy?',a:'The asset share AS_t is the actual accumulated fund per policy in force at time t, built from real premiums received, actual investment returns, and actual claims and expenses paid. It represents what the insurer actually holds, as opposed to the theoretical reserve. Comparing AS_t to the reserve reveals under- or over-funding.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'Write the asset share recursion.',a:'AS_t = (AS_{t−1} + P − e_t)(1+i^A) − (S+E_t)·q^A_{x+t−1}, where i^A = actual investment return, e_t = renewal expenses, S = death benefit, E_t = death claim expenses, q^A = actual mortality rate. Initial asset share is −(initial expense) since commission is paid upfront before any premium arrives.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is profit testing per unit sum assured?',a:'Divide every element of the profit vector (PRO_t) by the sum assured S. This normalises cashflows so products with different benefit levels can be compared on equal terms. It shows the profit (positive or negative) per £1 of cover, making it easier to identify structurally loss-making product designs.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the profit signature and explain how it is derived from the profit vector.',a:'The profit signature Π_t = PRO_t × (probability of being in force at start of year t). For a whole-life policy: Π_t = PRO_t × ₜ₋₁p_x. It converts per-surviving-policy profits to per-policy-issued profits, allowing NPV and IRR calculations as cashflows from the policyholder\'s issue date.'},
  {module:'CM1B',sub:'res-reserve',color:'#3D6FD1',topic:'Pricing & reserving',q:"What is Zillmer's method?",a:"Zillmer's adjustment modifies the net premium reserve to allow for heavy initial expenses (e.g. first-year commission). The Zillmer reserve = net premium reserve − α·(1 − A_{x+t:n−t|}), where α is the Zillmer adjustment (proportional to the initial expense). Early reserves become lower (or negative), repaid by an augmented net premium in later years. Negative reserves must be zeroed."},
  {module:'CM1B',sub:'res-grossprem',color:'#3D6FD1',topic:'Pricing & reserving',q:'Why can gross premium reserves be negative in early policy years, and why does this matter?',a:'Large initial expenses (commission, setup costs) mean the EPV of future outgo is less than the EPV of future premiums in early years, giving a negative reserve. Regulators prohibit negative reserves, so they are set to zero (zeroised); any resulting financing cost must be included in the premium or borne by the insurer as a capital strain.'},
  {module:'CM1B',sub:'res-mortality',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is the net amount at risk (NAAR)?',a:'NAAR = S − ₜV, the death benefit less the reserve held at the start of the policy year. The reserve is already set aside to help pay the claim; the insurer is exposed only to the difference. NAAR is used in computing the expected mortality cost: E[cost] = q_{x+t} × NAAR, and in analysing mortality profit.'},
  {module:'CM1B',sub:'res-reserve',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is the modified net premium reserve and how does it differ from the full net premium reserve?',a:'A modified reserve reduces the net premium in year 1 (and sometimes later years) to explicitly allow for heavy initial expenses, while increasing the net premium in other years to compensate. The Commissioner\'s method and Illinois Standard are examples. This avoids large initial deficits while keeping reserves non-negative; it differs from the full NP reserve which uses a single level net premium throughout.'},
  {module:'CM1B',sub:'res-unitlinked',color:'#3D6FD1',topic:'Pricing & reserving',q:'Distinguish the unit reserve from the non-unit reserve for a unit-linked contract.',a:'Unit reserve: the market value of units held in the policyholder\'s fund — it fluctuates with markets and belongs economically to the policyholder. Non-unit (sterling) reserve: the insurer\'s own reserve for future negative non-unit cashflows (e.g. top-up death benefit, expenses exceeding fund charges). Total gross premium reserve = unit reserve + non-unit reserve.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'What is the internal rate of return (IRR) in profit testing and how is it used?',a:'The IRR is the risk discount rate at which the NPV of the profit signature equals zero. If IRR > required risk discount rate (hurdle rate), the product earns a sufficient return on capital. It is used alongside profit margin (NPV of profit / EPV of premiums) and payback period to assess product profitability.'},
  {module:'CM1B',sub:'res-profit',color:'#3D6FD1',topic:'Pricing & reserving',q:'Define the profit margin in life insurance profit testing.',a:'Profit margin = NPV(profit signature) / EPV(premiums), both discounted at the risk discount rate. A positive profit margin means the product earns more than the cost of capital; it expresses profit as a fraction of premium income, enabling comparison across products of different premium sizes and contract lengths.'},

  // ── CS1B R-IMPLEMENTATION FLASHCARDS ─────────────────────────────────────
  {module:'CS1B',sub:'cs1b-reg-lm',color:'#2E9C8E',topic:'R: Fitting lm()',q:'How do you fit a linear regression in R and inspect the results?',a:'model <- lm(y ~ x1 + x2, data=df). Then summary(model) prints coefficients, SEs, t-values, p-values, R², and the F-statistic. coef(model) extracts the coefficient vector. Use confint(model) for 95% confidence intervals on coefficients.'},
  {module:'CS1B',sub:'cs1b-reg-lm',color:'#2E9C8E',topic:'R: Extracting model statistics',q:'How do you extract R², residual SE, and coefficient p-values from a fitted lm() in R?',a:'s <- summary(model). Then: R² = s$r.squared; adjusted R² = s$adj.r.squared; RSE = s$sigma; coefficient table (incl. p-values) = coef(s) or s$coefficients. The p-value for coefficient j is s$coefficients[j, "Pr(>|t|)"].'},
  {module:'CS1B',sub:'cs1b-reg-lm',color:'#2E9C8E',topic:'R: predict()',q:'How do you use predict() to get fitted values and intervals from an lm() model?',a:'predict(model, newdata=df_new) for point predictions on new data. Add interval="confidence", level=0.95 for a CI on the conditional mean E[Y|X]. Add interval="prediction" for a PI on a single new observation — always wider because it adds σ² to the variance of the estimate.'},
  {module:'CS1B',sub:'cs1b-reg-glm',color:'#2E9C8E',topic:'R: Fitting glm()',q:'How do you fit a Poisson GLM with a log-link and exposure offset in R?',a:'model <- glm(claims ~ x1 + x2, family=poisson(link="log"), offset=log(exposure), data=df). The offset adjusts for differing exposure so the response is modelled as a rate. exp(coef(model)) converts log-scale coefficients to multiplicative rate ratios. summary(model) shows deviance and AIC.'},
  {module:'CS1B',sub:'cs1b-reg-glm',color:'#2E9C8E',topic:'R: Comparing nested GLMs',q:'How do you compare two nested GLMs in R?',a:'anova(model_small, model_large, test="Chisq") performs a likelihood ratio test: the deviance difference ~ χ²(Δdf) under H₀. Alternatively, AIC(model) or BIC(model) for information criteria — lower is better. For non-nested models use AIC/BIC only; LRT (anova) requires one model to be a special case of the other.'},
  {module:'CS1B',sub:'cs1b-reg-diag',color:'#2E9C8E',topic:'R: Regression diagnostics',q:'How do you produce and interpret the 4 standard diagnostic plots for a linear model in R?',a:'par(mfrow=c(2,2)); plot(model). Four plots: (1) Residuals vs Fitted — checks linearity and homoscedasticity (want random scatter). (2) Normal Q-Q — checks normality of residuals (want points on diagonal). (3) Scale-Location — homoscedasticity (want flat line). (4) Residuals vs Leverage — identifies influential points via Cook\'s distance.'},
  {module:'CS1B',sub:'cs1b-inf-test',color:'#2E9C8E',topic:'R: t.test()',q:'How do you run one-sample and two-sample t-tests in R?',a:'One-sample: t.test(x, mu=mu0). Two-sample: t.test(x, y) (Welch, default) or t.test(x, y, var.equal=TRUE) (equal variances). One-sided: alternative="greater" or "less". Result includes t-statistic, df, p-value, and 95% CI. Access: result$p.value, result$conf.int.'},
  {module:'CS1B',sub:'cs1b-inf-test',color:'#2E9C8E',topic:'R: chisq.test()',q:'How do you run a chi-squared goodness-of-fit test in R?',a:'chisq.test(observed, p=expected_probs) where expected_probs sums to 1. The function returns X², df = k−1 (minus estimated parameters), and a p-value. Cells with expected counts < 5 should be merged first. For a contingency table use chisq.test(table) with no p= argument.'},
  {module:'CS1B',sub:'cs1b-rv-dist',color:'#2E9C8E',topic:'R: Distribution functions',q:'What is the d/p/q/r naming convention for distributions in R?',a:'For any distribution XYZ: dxyz(x,...) is the density/PMF; pxyz(q,...) is the CDF P(X≤q); qxyz(p,...) is the quantile (inverse CDF); rxyz(n,...) simulates n random values. Examples: dnorm/pnorm/qnorm/rnorm (Normal), dpois/ppois/qpois/rpois (Poisson), dgamma/pgamma/qgamma/rgamma (Gamma), dbeta/pbeta/qbeta/rbeta (Beta).'},
  {module:'CS1B',sub:'cs1b-rv-dist',color:'#2E9C8E',topic:'R: Poisson distribution',q:'How do you simulate from and compute probabilities for a Poisson distribution in R?',a:'rpois(n, lambda) simulates n values. dpois(k, lambda) gives P(X=k). ppois(q, lambda) gives P(X≤q). Example: P(X=3 | λ=2) = dpois(3,2) ≈ 0.180. To test if data is Poisson: check mean ≈ var (dispersion test: var(x)/mean(x) near 1) and use chisq.test() for a formal goodness-of-fit test.'},
];

